function uid(){return (crypto.randomUUID?crypto.randomUUID():Date.now().toString(36)+Math.random().toString(36).slice(2));}
function today(){const d=new Date(); const y=d.getFullYear(); const m=String(d.getMonth()+1).padStart(2,'0'); const day=String(d.getDate()).padStart(2,'0'); return `${y}-${m}-${day}`}
function money(n){return '$'+Math.round(Number(n)||0).toLocaleString('es-CL')}
function kmFmt(n){n=Number(n)||0; return n>=1000?Math.round(n/1000)+'K':String(n)}
function esc(s){return String(s??'').replace(/[&<>"]/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[m]))}
function addMonths(dateStr,m){if(!dateStr||!m)return null; const d=new Date(dateStr+'T12:00:00'); if(isNaN(d))return null; d.setMonth(d.getMonth()+Number(m)); return d.toISOString().slice(0,10)}
function daysUntil(dateStr){if(!dateStr)return null; const a=new Date(today()+'T00:00:00'); const b=new Date(dateStr+'T00:00:00'); if(isNaN(b))return null; return Math.ceil((b-a)/86400000)}
function categoryGroup(c){c=String(c||'Otros').toLowerCase(); if(c.includes('document'))return 'Documentos'; if(c.includes('suspensi')||c.includes('amortigu'))return 'Suspensión'; if(c.includes('servicio')||c.includes('mantenci')||c.includes('revisión')||c.includes('revision')||c.includes('emisi')||c.includes('diagn'))return 'Servicio'; if(c.includes('fluido')||c.includes('líquido')||c.includes('liquido')||c.includes('nivel')||c.includes('lavacristales'))return 'Fluidos'; if(c.includes('transmisi')||c.includes('cambio')||c.includes('dualogic')||c.includes('embrague'))return 'Transmisión'; if(c.includes('motor')||c.includes('eléctr')||c.includes('electr')||c.includes('bater')||c.includes('correa')||c.includes('buj'))return 'Motor'; if(c.includes('rueda')||c.includes('neum')||c.includes('aline'))return 'Ruedas'; if(c.includes('freno'))return 'Frenos'; if(c.includes('luz')||c.includes('luces'))return 'Luces'; if(c.includes('carro')||c.includes('exterior')||c.includes('limpia')||c.includes('escobilla')||c.includes('cerradura'))return 'Exterior'; return 'Otros'}
function isDoc(i){return !!i.document || categoryGroup(i.category)==='Documentos'}
function itemById(id){return data.items.find(i=>i.id===id)}
function recordsOf(id){return data.records.filter(r=>r.itemId===id).sort((a,b)=>String(b.date||'').localeCompare(String(a.date||'')) || String(b.createdAt||'').localeCompare(String(a.createdAt||'')))}
function serviceRecordsOf(id){return recordsOf(id).filter(r=>!r.quickCheck)}
function lastRecord(id){return recordsOf(id)[0]||null}
function lastServiceRecord(id){return serviceRecordsOf(id)[0]||null}
function lastServiceKmRecord(id){return serviceRecordsOf(id).find(r=>Number(r.km)>0)||lastServiceRecord(id)}
function recordById(id){return data.records.find(r=>r.id===id)}
