function defaultData(){return {app:'Mi Auto al Día',version:2,exportedAt:new Date().toISOString(),vehicle:{name:'Fiat Punto',year:'2017',plate:'',currentKm:0,image:DEFAULT_IMG},items:defaultItems(),records:[],settings:{appTitle:'Mi Auto al Día',warnDays:30,warnKm:1000}}}
function migrate(d){const base=defaultData(); d=d||{}; d.vehicle={...base.vehicle,...(d.vehicle||{})}; if(['vehicle_default.jpg','vehicle_default_cut.png','app_icon_car.png'].includes(d.vehicle.image)) d.vehicle.image=DEFAULT_IMG; d.settings={...base.settings,...(d.settings||{})}; d.items=Array.isArray(d.items)?d.items:[]; d.records=Array.isArray(d.records)?d.records:[]; const defaults=Object.fromEntries(base.items.map(i=>[i.id,i])); const byId=Object.fromEntries(d.items.map(i=>[i.id,i])); base.items.forEach(b=>{ if(!byId[b.id]) d.items.push({...b}); }); d.items=d.items.map(i=>{ if(i.id==='driving_permit' && i.name==='Permiso de conducción') i.name='Permiso de circulación'; const def=defaults[i.id]; if(def){ const old={...i}; i={...def,...old}; if(old.x===undefined&&def.x!==undefined)i.x=def.x; if(old.y===undefined&&def.y!==undefined)i.y=def.y; i.name=old.name||def.name; i.category=old.category||def.category; i.points=old.points&&Object.keys(old.points).length?old.points:(def.points||{}); if(['oil','oil_filter'].includes(i.id)){i.intervalKm=def.intervalKm;i.intervalMonths=def.intervalMonths;i.note=def.note;i.source=def.source;} if(def.document){i.document=true;i.intervalKm=null;i.intervalMonths=null;} } i.points=i.points||{}; if(categoryGroup(i.category)==='Documentos'){i.document=true;i.intervalKm=null;i.intervalMonths=null;} return i}); d.version=base.version; return {...base,...d};}
function loadData(){try{const raw=localStorage.getItem(STORAGE_KEY); return raw?migrate(JSON.parse(raw)):defaultData()}catch(e){return defaultData()}}
function vehicleSrc(){const img=data?.vehicle?.image||DEFAULT_IMG; return ['vehicle_default.jpg','vehicle_default_cut.png','app_icon_car.png'].includes(img)?DEFAULT_IMG:img}
function escAttr(v){return esc(v).replace(/"/g,'&quot;').replace(/'/g,'&#39;')}
function save(){data.exportedAt=new Date().toISOString(); try{localStorage.setItem(STORAGE_KEY,JSON.stringify(data));}catch(e){alert('No se pudo guardar: hay demasiados datos o una imagen muy pesada.')}}


function humanDuration(days){
 const abs=Math.abs(Number(days)||0);
 if(abs>=365){const y=Math.floor(abs/365); return `${y} año${y!==1?'s':''}`;}
 if(abs>=30){const m=Math.floor(abs/30); return `${m} mes${m!==1?'es':''}`;}
 return `${abs} día${abs!==1?'s':''}`;
}

function statusOf(item){const rec=isDoc(item)?lastRecord(item.id):lastServiceRecord(item.id); const kmRec=!isDoc(item)?lastServiceKmRecord(item.id):rec; const warnDays=Number(data.settings.warnDays||30); const warnKm=Number(data.settings.warnKm||1000); if(isDoc(item)){ if(!rec||!rec.expiryDate)return {state:'unknown',label:'Sin dato',detail:'Registra vencimiento'}; const d=daysUntil(rec.expiryDate); if(d===null)return {state:'unknown',label:'Sin dato',detail:'Fecha inválida'}; if(d<0)return {state:'critical',label:'Vencido',detail:`Hace ${humanDuration(d)}`}; if(d<=warnDays)return {state:'warning',label:'Pronto',detail:`Faltan ${d} días`}; return {state:'ok',label:'Al día',detail:`Vence ${fmtDate(rec.expiryDate)}`}; }
 if(!rec)return {state:'unknown',label:'Sin dato',detail:'Sin registro'};
 let dueDate=item.intervalMonths?addMonths(rec.date,item.intervalMonths):null; let days=dueDate?daysUntil(dueDate):null; let kmLeft=null;
 if(item.intervalKm && kmRec && Number(kmRec.km)>0 && Number(data.vehicle.currentKm)>0) kmLeft=Number(item.intervalKm)-(Number(data.vehicle.currentKm)-Number(kmRec.km));
 let crit=false,warn=false,details=[];
 if(days!==null){ if(days<0)crit=true; else if(days<=warnDays)warn=true; details.length=0;details.push(days<0?`Vencida hace ${humanDuration(days)}`:`Próxima en ${humanDuration(days)}`); }
 if(kmLeft!==null){ if(kmLeft<=0)crit=true; else if(kmLeft<=warnKm)warn=true; details.push(kmLeft<=0?`km vencido ${Math.abs(kmLeft)}`:`${Math.round(kmLeft).toLocaleString('es-CL')} km`); }
 if(crit)return {state:'critical',label:'Crítico',detail:details.join(' · ')||'Vencido'};
 if(warn)return {state:'warning',label:'Pronto',detail:details.join(' · ')||'Próximo'};
 return {state:'ok',label:'Al día',detail:details.join(' · ')||`Último ${fmtDate(rec.date)}`};}
function fmtDate(d){if(!d)return 'sin fecha'; const [y,m,day]=String(d).split('-'); return day&&m?`${day}-${m}-${y}`:String(d)}
function intervalText(i){const km=i.intervalKm?Number(i.intervalKm).toLocaleString('es-CL')+' km':''; const mo=i.intervalMonths?(i.intervalMonths===12?'1 año':i.intervalMonths+' meses'):''; if(km&&mo)return km+' / '+mo; return km||mo||'sin intervalo'}
function health(){const non=data.items.filter(i=>!isDoc(i)); const known=non.map(statusOf).filter(s=>s.state!=='unknown'); if(!known.length)return 0; const score=known.reduce((a,s)=>a+(s.state==='ok'?100:s.state==='warning'?60:s.state==='critical'?15:0),0)/known.length; return Math.round(score)}
function counts(){const mechanical=data.items.filter(i=>!isDoc(i)).map(statusOf); const docs=data.items.filter(isDoc).map(statusOf); return {critical:[...mechanical,...docs].filter(s=>s.state==='critical').length,warning:[...mechanical,...docs].filter(s=>s.state==='warning').length,ok:[...mechanical,...docs].filter(s=>s.state==='ok').length,unknown:[...mechanical,...docs].filter(s=>s.state==='unknown').length,docsUnknown:docs.filter(s=>s.state==='unknown').length}}
function ranked(){return data.items.map(i=>({item:i,st:statusOf(i),rec:isDoc(i)?lastRecord(i.id):lastServiceRecord(i.id)})).sort((a,b)=>({critical:0,warning:1,unknown:2,ok:3}[a.st.state]-{critical:0,warning:1,unknown:2,ok:3}[b.st.state]));}
function stateColor(st){return st==='ok'?'var(--green)':st==='warning'?'var(--warning)':st==='critical'?'var(--danger)':'#94a3b8'}
function dotClass(st){return st==='ok'?'ok':st==='warning'?'warning':st==='critical'?'critical':'unknown'}
function usesEngineMap(){return ['Motor','Fluidos','Transmisión'].includes(cat)}
const QUICK_CHECK_IDS=new Set(['oil','oil_filter','oil_level_check','coolant','brake_fluid_level','washer_fluid','fluid_levels','tires','lights_front','lights_rear','lights_system','wipers','battery','front_brakes','rear_brakes','alignment','front_shocks','rear_shocks']);
function supportsQuickCheck(item){return !!item && !isDoc(item) && (item.quickCheckable===true || QUICK_CHECK_IDS.has(item.id))}
function quickCheck(itemId){const item=itemById(itemId); if(!supportsQuickCheck(item))return; const rec={id:uid(),itemId:item.id,date:today(),km:Number(data.vehicle.currentKm)||null,cost:0,shop:'',notes:'Chequeo rápido: revisado. No reinicia vida útil.',quickCheck:true,createdAt:new Date().toISOString()}; data.records.unshift(rec); save(); toast(item.name+' revisado sin reiniciar vencimiento'); document.querySelectorAll('.screen').forEach(x=>x.classList.toggle('active',x.id===view));
render(); if(String(modal||'').startsWith('item:'+item.id)) openItem(item.id,'summary');}
function systemTags(counts){const tags=[]; if(counts.critical)tags.push(`<span class="system-tag critical">${counts.critical} pendiente${counts.critical>1?'s':''}</span>`); if(counts.warning)tags.push(`<span class="system-tag warning">${counts.warning} próxima${counts.warning>1?'s':''}</span>`); if(counts.ok)tags.push(`<span class="system-tag ok">${counts.ok} OK</span>`); if(counts.unknown)tags.push(`<span class="system-tag unknown">${counts.unknown} sin dato</span>`); return tags.join('')||'<span class="system-tag ok">Sin alertas</span>'}

function iconForCategory(c){const g=categoryGroup(c); return ({Motor:'🛢',Frenos:'🛞',Ruedas:'◌',Fluidos:'💧',Suspensión:'〰',Servicio:'🧰',Transmisión:'⚙',Luces:'💡',Exterior:'🚗',Documentos:'📄',Otros:'•'})[g]||'•'}
function accentForCategory(c){const g=categoryGroup(c); return ({Motor:'var(--green)',Frenos:'var(--purple)',Ruedas:'var(--warning)',Fluidos:'var(--teal2)',Suspensión:'#79f2ff',Servicio:'var(--teal)',Transmisión:'var(--pink)',Luces:'#8eb8ff',Exterior:'#8ea9c4',Documentos:'#7d8ea6',Otros:'#7d8ea6'})[g]||'var(--teal)'}
function stateLabel(st){return st==='ok'?'Completada':st==='warning'?'Próxima':st==='critical'?'Vencida':'Sin registro'}
function healthText(v){return v>=90?'Excelente':v>=70?'Buena':v>=45?'Atención':'Crítica'}
function nextServiceCandidate(){return ranked().find(x=>!isDoc(x.item)&&x.st.state!=='ok')||ranked().find(x=>!isDoc(x.item))||null}
function nextServiceSummary(){const x=nextServiceCandidate(); if(!x) return {title:'Sin mantenciones pendientes', line1:'Todo al día', line2:'Revisa el historial para más detalle'}; return {title:x.item.name, line1:x.st.detail||intervalText(x.item), line2:intervalText(x.item)} }
function statusMetrics(item){const rec=isDoc(item)?lastRecord(item.id):lastServiceRecord(item.id); const kmRec=!isDoc(item)?lastServiceKmRecord(item.id):rec; let dueDate=item.intervalMonths&&rec?addMonths(rec.date,item.intervalMonths):null; let days=item.intervalMonths&&rec?daysUntil(dueDate):null; let kmLeft=null; if(item.intervalKm && kmRec && Number(kmRec.km)>0 && Number(data.vehicle.currentKm)>=0) kmLeft=Number(item.intervalKm)-(Number(data.vehicle.currentKm)-Number(kmRec.km)); return {rec,kmRec,dueDate,days,kmLeft};}
function serviceDueText(item){const m=statusMetrics(item); const p=[]; if(m.kmLeft!==null) p.push((m.kmLeft>0?Math.round(m.kmLeft).toLocaleString('es-CL'):'0')+' km'); if(m.days!==null) p.push((m.days>0?m.days:'0')+' días'); return p.join(' · ')||'Sin registro'}
function serviceRight(item,st){const m=statusMetrics(item); let kmTxt='—'; let dayTxt='—'; if(m.kmLeft!==null){kmTxt=m.kmLeft<=0?'0 km':Math.round(m.kmLeft).toLocaleString('es-CL')+' km'} if(m.days!==null){dayTxt=m.days<=0?'0 días':m.days+' días'} if(st.state==='critical'){ if(m.kmLeft!==null){ kmTxt='Revisar'; dayTxt=Math.abs(Math.round(m.kmLeft||0)).toLocaleString('es-CL')+' km excedidos'; } if(m.days!==null){ kmTxt='Revisar'; dayTxt=m.days<0?`hace ${Math.abs(m.days)} días`:'hoy'; } }
  return {top:kmTxt,bottom:dayTxt}; }
function progressData(item){const m=statusMetrics(item); let pct=0; if(item.intervalKm && m.kmLeft!==null){ pct=100-Math.max(0,Math.min(100,(m.kmLeft/Number(item.intervalKm))*100)); }
 else if(item.intervalMonths && m.days!==null){ const total=Math.max(1,Number(item.intervalMonths)*30); pct=100-Math.max(0,Math.min(100,(m.days/total)*100)); }
 return {pct:Math.max(8,Math.min(100,Math.round(pct))), ...m}; }
function maintenanceCounts(){const arr=data.items.filter(i=>!isDoc(i)).map(statusOf);return {critical:arr.filter(s=>s.state==='critical').length,warning:arr.filter(s=>s.state==='warning').length,ok:arr.filter(s=>s.state==='ok').length,unknown:arr.filter(s=>s.state==='unknown').length,total:arr.length};}
function maintenanceCategories(){const set=new Set(['Todas']); data.items.filter(i=>!isDoc(i)).forEach(i=>set.add(categoryGroup(i.category))); return Array.from(set);}
function maintenanceItemsByTab(){ let arr=data.items.filter(i=>!isDoc(i)).map(i=>({item:i,st:statusOf(i),rec:lastServiceRecord(i.id)})); if(maintenanceCategory&&maintenanceCategory!=='Todas') arr=arr.filter(x=>categoryGroup(x.item.category)===maintenanceCategory); const order={critical:0,warning:1,unknown:2,ok:3}; arr.sort((a,b)=>order[a.st.state]-order[b.st.state] || String(a.item.name).localeCompare(String(b.item.name))); if(maintenanceTab==='upcoming') return arr.filter(x=>x.st.state==='warning'); if(maintenanceTab==='overdue') return arr.filter(x=>x.st.state==='critical'); if(maintenanceTab==='done') return arr.filter(x=>x.st.state==='ok' && x.rec); return arr; }
function monthLabel(d){return d.toLocaleDateString('es-CL',{month:'long',year:'numeric'})}
function buildCalendar(){ const now=new Date(); const y=now.getFullYear(), m=now.getMonth(); const first=new Date(y,m,1); const start=(first.getDay()+6)%7; const days=new Date(y,m+1,0).getDate(); const events=new Set(calendarEvents(16).map(e=>{ const dd=new Date(e.when+'T00:00:00'); return isNaN(dd)||dd.getMonth()!==m?0:dd.getDate(); }).filter(Boolean)); let html='<div class="calendar-card calendar-compact"><div class="calendar-head"><button class="icon-btn" onclick="toast(\'Vista mensual\')">‹</button><div class="calendar-title">'+monthLabel(now)+'</div><button class="icon-btn" onclick="toast(\'Vista mensual\')">›</button></div><div class="calendar-grid">'; ['LUN','MAR','MIÉ','JUE','VIE','SÁB','DOM'].forEach(n=> html+='<div class="dayname">'+n+'</div>'); for(let i=0;i<start;i++) html+='<div class="day muted"></div>'; for(let d=1; d<=days; d++){ const cls=['day']; if(d===now.getDate()) cls.push('today'); else if(events.has(d)) cls.push('event'); html+='<div class="'+cls.join(' ')+'">'+d+'</div>'; } html+='</div></div>'; return html; }
function calendarEvents(limit=12){ const ev=[]; data.items.forEach(i=>{ const st=statusOf(i); if(isDoc(i)){ const rec=lastRecord(i.id); if(rec&&rec.expiryDate) ev.push({item:i,when:rec.expiryDate,state:st.state,kind:'doc'}); return; } const m=statusMetrics(i); if(m.rec&&m.dueDate) ev.push({item:i,when:m.dueDate,state:st.state,kind:'date'}); }); ev.sort((a,b)=>{ const ao=a.state==='critical'?0:1, bo=b.state==='critical'?0:1; return ao-bo || String(a.when).localeCompare(String(b.when)); }); return ev.slice(0,limit); }
function nextEvents(limit=6){ return calendarEvents(limit).filter(e=>!isDoc(e.item)); }
function zoneSummary(){return ['Motor','Frenos','Fluidos','Ruedas','Luces','Batería'].map(name=>{ const base=name==='Batería'?'Motor':name; const arr=data.items.filter(i=>!isDoc(i)&&categoryGroup(i.category)===base).map(statusOf); const state=arr.some(s=>s.state==='critical')?'critical':arr.some(s=>s.state==='warning')?'warning':arr.some(s=>s.state==='unknown')?'unknown':'ok'; return {name,state};});}
function rowItem(item,st,click=true){ const due=serviceRight(item,st); const p=progressData(item); const meta=st.state==='critical'||st.state==='warning'?st.detail:intervalText(item); return `<div class="maint-row compact" ${click?`onclick="openItem('${item.id}')"`:''}><div class="maint-left"><div class="icon-badge circle" style="color:${accentForCategory(item.category)}">${iconForCategory(item.category)}</div><div class="row-main"><b>${esc(item.name)}</b><small>${esc(intervalText(item))} · ${esc(meta)}</small><div class="mini-progress" style="--pct:${p.pct}%"><span></span></div></div></div><div class="row-side"><div class="due-stack ${st.state}"><b>${esc(due.top)}</b><small>${esc(due.bottom)}</small></div>${supportsQuickCheck(item)?`<button class="check-action" onclick="event.stopPropagation();quickCheck('${item.id}')" title="Chequeo rápido: no reinicia vencimiento">✅</button>`:''}</div></div>` }
function rowDoc(item){const st=statusOf(item); const rec=lastRecord(item.id); return `<div class="row" onclick="openDoc('${item.id}')"><div class="maint-left"><div class="icon-badge circle" style="color:#8ea9c4">📄</div><div class="row-main"><b>${esc(item.name)}</b><small>${rec&&rec.expiryDate?`Vence ${fmtDate(rec.expiryDate)}`:'Sin vencimiento registrado'}${rec&&rec.issueDate?` · Otorgado ${fmtDate(rec.issueDate)}`:''}</small></div></div><span class="status ${st.state}">${stateLabel(st.state)}</span></div>`}
function go(s){
 if(shouldNavigateToPage(s)){ window.location.href=PAGE_ROUTES[s]; return; }
 view=s;
 document.querySelectorAll('.screen').forEach(x=>x.classList.toggle('active',x.id===s));
 render();
}
function render(){const navViews=['home','parts',null,'docs','settings']; document.querySelectorAll('#nav button').forEach((b,i)=>b.classList.toggle('active',navViews[i]===view)); try{ if(view==='home')renderHome(); if(view==='parts')renderParts(); if(view==='docs')renderDocs(); if(view==='history')renderHistory(); if(view==='settings')renderSettings(); }catch(err){ console.error(err); const el=document.getElementById(view)||document.getElementById('home'); if(el)el.innerHTML=`<div class="topbar-dual"><button class="back" onclick="go('home')">‹</button><h1 class="brand">ERROR</h1><button class="ghost-btn"></button></div><div class="empty">No se pudo cargar esta seccion.<br><small>${esc(err&&err.message?err.message:String(err))}</small></div>`; }}
function renderHome(){
 const next=nextServiceSummary();
 const h=health();
 const c=maintenanceCounts();
 const candidate=nextServiceCandidate();
 const m=candidate?statusMetrics(candidate.item):null;
 const alerts=ranked().filter(x=>x.st.state!=='ok' && !isDoc(x.item)).slice(0,3);
 const now=new Date();
 const time=now.toLocaleTimeString('es-CL',{hour:'2-digit',minute:'2-digit'});
 const monthKey=now.toISOString().slice(0,7);
 const monthEvents=data.records.filter(r=>String(r.date||'').slice(0,7)===monthKey).length;
 const totalServices=data.records.filter(r=>!r.quickCheck).length;
 const nextDays=m&&m.days!==null?Math.max(0,Math.round(m.days)):'—';
 const nextKm=m&&m.kmLeft!==null?Math.max(0,Math.round(m.kmLeft)).toLocaleString('es-CL'):'—';
 const candidateAction=candidate?"openItem('"+candidate.item.id+"')":"go('parts')";
 document.getElementById('home').innerHTML=`
 <div class="topbar-home"><button class="back" onclick="go('settings')">☰</button><div class="brand-center"><div class="topbar-title">MI AUTO</div><span class="sub-brand">AL DÍA</span></div><button class="gear" onclick="go('settings')">🔔</button></div>
 <div class="home-vehicle-compact saas-hero" onclick="openVehicleSettings()"><div class="hero-copy"><div class="vehicle-name">${esc(data.vehicle.name||'Vehículo')}</div><div class="vehicle-line"><span>${esc(data.vehicle.year||'')}</span><span>·</span><span>${esc(data.vehicle.plate||'Sin patente')}</span></div><div class="vehicle-km"><span>Kilometraje actual</span><b>${Number(data.vehicle.currentKm||0).toLocaleString('es-CL')} km</b><small>Actualizado hoy, ${time}</small></div></div><div class="mini-car"><img src="${escAttr(vehicleSrc())}" alt="vehículo"></div></div>
 <div class="saas-status-strip"><div class="saas-metric critical"><span>Vencidas</span><b>${c.critical}</b><small>!</small></div><div class="saas-metric warning"><span>Próximas</span><b>${c.warning}</b><small>▣</small></div><div class="saas-metric ok"><span>Al día</span><b>${c.ok}</b><small>✓</small></div><div class="saas-metric unknown"><span>Sin dato</span><b>${c.unknown}</b><small>?</small></div></div>
 <div class="health-trend-card"><div><div class="section-cap">Salud general</div><div class="gauge" style="--value:${h}"><div class="gauge-inner"><div><b>${h}%</b><em>${healthText(h)}</em></div></div></div></div><div class="trend-area"><svg class="health-chart" viewBox="0 0 240 92" preserveAspectRatio="none"><defs><linearGradient id="healthFill" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="#24f0c9" stop-opacity=".48"/><stop offset="1" stop-color="#24f0c9" stop-opacity="0"/></linearGradient></defs><path class="fill" d="M0 70 L24 58 L48 62 L72 44 L96 36 L120 56 L144 66 L168 48 L192 47 L216 34 L240 28 L240 92 L0 92 Z"/><path class="line" d="M0 70 L24 58 L48 62 L72 44 L96 36 L120 56 L144 66 L168 48 L192 47 L216 34 L240 28"/><circle class="dot" cx="240" cy="28" r="5"/></svg><div class="chart-labels"><span>MAY</span><span>JUN</span><span>JUL</span><span>AGO</span><span>SEP</span><span>OCT</span></div></div></div>
 <div class="saas-kpi-grid"><div class="saas-kpi"><span>Próximo servicio</span><i>▣</i><b>${nextDays}</b><small>${nextDays==='—'?'sin fecha':'días'}</small></div><div class="saas-kpi"><span>Km. estimado</span><i>◌</i><b>${nextKm}</b><small>${nextKm==='—'?'sin dato':'km restantes'}</small></div><div class="saas-kpi"><span>Eventos</span><i>▤</i><b>${monthEvents}</b><small>este mes</small></div><div class="saas-kpi"><span>Total servicios</span><i>⌁</i><b>${totalServices}</b><small>historial</small></div></div>
 <div class="home-alerts"><div class="section-split"><div class="section-cap">Alertas importantes</div><button class="text-link" onclick="go('parts')">Ver todas</button></div><div class="list compact-list">${alerts.length?alerts.map(x=>rowItem(x.item,x.st,false).replace('maint-row compact','maint-row compact alert-mini')).join(''):'<div class="empty">Todo lo registrado está al día.</div>'}</div></div>
 <div class="control-card"><div class="control-shield">✓</div><div class="control-copy"><b>Tu auto, bajo control</b><small>Llevar al día los mantenimientos aumenta la vida útil de tu auto y tu seguridad.</small></div><button onclick="${candidateAction}">Ver recomendaciones</button></div>`;
}
function systemStats(name){ const arr=data.items.filter(i=>!isDoc(i)&&categoryGroup(i.category)===name).map(i=>({item:i,st:statusOf(i),rec:lastRecord(i.id)})); const counts={critical:0,warning:0,ok:0,unknown:0}; arr.forEach(x=>counts[x.st.state]++); const order={critical:0,warning:1,unknown:2,ok:3}; arr.sort((a,b)=>order[a.st.state]-order[b.st.state]||String(a.item.name).localeCompare(String(b.item.name))); const state=counts.critical?'critical':counts.warning?'warning':counts.unknown?'unknown':'ok'; return {name,arr,counts,total:arr.length,state,top:arr[0]}; }
function systemCard(name){ const s=systemStats(name); const color=accentForCategory(name); const active=maintenanceCategory===name; const label=s.counts.critical?`${s.counts.critical} pendiente${s.counts.critical>1?'s':''}`:s.counts.warning?`${s.counts.warning} próxima${s.counts.warning>1?'s':''}`:s.counts.unknown?`${s.counts.unknown} sin dato`:`${s.counts.ok} OK`; return `<button class="system-card ${active?'active':''}" style="color:${color}" onclick="maintenanceCategory='${name}';maintenanceExpanded=false;renderParts()"><div class="system-head"><div class="system-ico">${iconForCategory(name)}</div><span class="system-count">${s.total}</span></div><h3>${esc(name)}</h3><p>${esc(label)}</p></button>`; }
function focusRow(x){ const due=serviceRight(x.item,x.st); return `<div class="focus-card" onclick="openItem('${x.item.id}')"><div class="focus-top"><div class="focus-title"><div class="icon-badge circle" style="color:${accentForCategory(x.item.category)}">${iconForCategory(x.item.category)}</div><div><b>${esc(x.item.name)}</b><small>${esc(categoryGroup(x.item.category))} · ${esc(x.st.detail||intervalText(x.item))}</small></div></div><div class="focus-state ${x.st.state}">${stateLabel(x.st.state)}<br><small>${esc(due.bottom)}</small></div></div><div class="mini-progress" style="--pct:${progressData(x.item).pct}%"><span></span></div></div>`; }
function renderParts(){ const c=maintenanceCounts(); const cats=maintenanceCategories().filter(n=>n!=='Todas'); const urgent=ranked().filter(x=>!isDoc(x.item)&&(x.st.state==='critical'||x.st.state==='warning')).slice(0,4); let list=maintenanceItemsByTab(); const selected=maintenanceCategory!=='Todas'; const showList=selected||maintenanceTab!=='all'; const limit=selected?8:10; const visible=maintenanceExpanded?list:list.slice(0,limit); const hidden=Math.max(0,list.length-visible.length); const tabs=[['all','Todos'],['overdue','Pendientes'],['upcoming','Próximas'],['done','OK']].map(([id,label])=>`<button class="seg ${maintenanceTab===id?'active':''}" onclick="maintenanceTab='${id}';maintenanceExpanded=false;renderParts()">${label}</button>`).join(''); const listTitle=selected?maintenanceCategory:maintenanceTab==='overdue'?'Pendientes':maintenanceTab==='upcoming'?'Próximas':'Completadas'; document.getElementById('parts').innerHTML=`<div class="topbar-dual"><button class="back" onclick="go('home')">‹</button><h1 class="brand">MANTENCIONES</h1><button class="icon-btn" onclick="maintenanceCategory='Todas';maintenanceTab='all';maintenanceExpanded=false;renderParts()">⌕</button></div><div class="compact-intro"><div class="summary-chip critical"><span>Pendientes</span><b>${c.critical}</b></div><div class="summary-chip warning"><span>Próximas</span><b>${c.warning}</b></div><div class="summary-chip ok"><span>OK</span><b>${c.ok}</b></div><div class="summary-chip unknown"><span>Sin dato</span><b>${c.unknown}</b></div></div><div class="maintenance-tabs">${tabs}</div>${urgent.length&&!selected&&maintenanceTab==='all'?`<div class="section-split"><div class="section-cap">Requieren atención</div><button class="text-link" onclick="maintenanceTab='overdue';renderParts()">Ver pendientes</button></div><div class="maintenance-focus">${urgent.map(focusRow).join('')}</div>`:''}<div class="section-split"><div class="section-cap">Sistemas del vehículo</div>${selected?`<button class="system-clear" onclick="maintenanceCategory='Todas';maintenanceExpanded=false;renderParts()">Ver todos</button>`:'<span class="tiny">Toca para filtrar</span>'}</div><div class="system-grid">${cats.map(systemCard).join('')}</div>${showList?`<div class="section-split tight"><div class="section-cap">${esc(listTitle)} (${list.length})</div><button class="text-link" onclick="openRegister('${selected?maintenanceCategory:''}')">Registrar</button></div><div class="list compact-list">${visible.map(x=>rowItem(x.item,x.st)).join('')||'<div class="empty">No hay elementos en esta vista.</div>'}</div>${hidden?`<button class="btn full" onclick="maintenanceExpanded=true;renderParts()">Mostrar ${hidden} más</button>`:''}`:''}`; }

function calendarGroupLabel(dateStr){ const d=daysUntil(dateStr); if(d===null)return 'Sin fecha'; if(d<0)return 'Vencidas'; if(d===0)return 'Hoy'; if(d<=30)return 'Proximos 30 dias'; return 'Mas adelante'; }
function eventMonth(dateStr){ const d=new Date(String(dateStr||'')+'T00:00:00'); if(isNaN(d))return '--'; return d.toLocaleDateString('es-CL',{month:'short'}).replace('.',''); }
function eventDay(dateStr){ const d=new Date(String(dateStr||'')+'T00:00:00'); if(isNaN(d))return '--'; return String(d.getDate()).padStart(2,'0'); }
function nextDayStrip(){ const now=new Date(today()+'T00:00:00'); let html=''; const ev=calendarEvents(80); for(let i=0;i<10;i++){ const d=new Date(now); d.setDate(now.getDate()+i); const iso=d.toISOString().slice(0,10); const count=ev.filter(e=>e.when===iso).length; html+=`<div class="date-pill ${i===0?'today':''}" onclick="toast('${count?count+' evento(s)':'Sin eventos'}')"><div><small>${d.toLocaleDateString('es-CL',{weekday:'short'}).slice(0,3)}</small><b>${d.getDate()}</b></div></div>`; } return html; }
function reminderSetting(key,def=true){ data.settings=data.settings||{}; if(typeof data.settings[key]==='undefined') data.settings[key]=def; return !!data.settings[key]; }
function toggleSetting(key){ data.settings[key]=!reminderSetting(key,true); save(); renderSettings(); }

function renderAgendaRow(e){ const st=statusOf(e.item); const label=e.kind==='doc'?'Documento':'Mantención'; return `<div class="agenda-row" onclick="${isDoc(e.item)?`openDoc('${e.item.id}')`:`openItem('${e.item.id}')`}"><div class="agenda-date"><span>${eventMonth(e.when)}</span><b>${eventDay(e.when)}</b></div><div class="agenda-copy"><b>${esc(e.item.name)}</b><small>${label} · ${esc(categoryGroup(e.item.category))} · ${esc(st.detail||'')}</small></div><span class="status ${st.state}">${stateLabel(st.state)}</span></div>`; }
function renderDocChip(item){ const st=statusOf(item); const rec=lastRecord(item.id); return `<div class="doc-chip" onclick="openDoc('${item.id}')"><div class="icon-badge circle" style="color:#8ea9c4">📄</div><div><b>${esc(item.name)}</b><small>${rec&&rec.expiryDate?'Vence '+fmtDate(rec.expiryDate):'Sin vencimiento'} · ${stateLabel(st.state)}</small></div></div>`; }
function openDocumentsModal(){ const docs=data.items.filter(isDoc); document.getElementById('modalRoot').innerHTML=`<div class="modal"><div class="modal-card compact-modal"><div class="modal-head"><h2>Documentos</h2><button class="close" onclick="closeModal()">×</button></div><div class="compact-modal-list">${docs.map(rowDoc).join('')||'<div class="empty">Sin documentos.</div>'}</div></div></div>`; }
function renderDocs(){ const all=calendarEvents(80); const next=all.find(e=>daysUntil(e.when)>=0)||all[0]; const timeline=calendarExpanded?all:all.slice(0,8); const hidden=Math.max(0,all.length-timeline.length); const docItems=data.items.filter(isDoc); document.getElementById('docs').innerHTML=`<div class="topbar-dual"><button class="back" onclick="go('home')">‹</button><h1 class="brand">AGENDA</h1><button class="icon-btn" onclick="calendarExpanded=!calendarExpanded;renderDocs()">${calendarExpanded?'−':'+'}</button></div>${buildCalendar()}<div class="agenda-hero"><div class="agenda-main" onclick="${next?(isDoc(next.item)?`openDoc('${next.item.id}')`:`openItem('${next.item.id}')`):'toast(\'Sin eventos\')'}"><div class="date-badge"><div><span>${next?eventMonth(next.when):'--'}</span><b>${next?eventDay(next.when):'--'}</b></div></div><div class="copy"><b>${next?esc(next.item.name):'Sin eventos próximos'}</b><small>${next?esc(calendarGroupLabel(next.when)+' · '+categoryGroup(next.item.category)):'Registra mantenciones para llenar la agenda'}</small></div></div><div class="agenda-stat" onclick="openDocumentsModal()"><span>Docs</span><b>${docItems.length}</b></div></div><div class="date-strip">${nextDayStrip()}</div><div class="section-split"><div class="section-cap">Timeline</div><button class="text-link" onclick="go('parts')">Técnica</button></div><div class="agenda-timeline">${timeline.map(renderAgendaRow).join('')||'<div class="empty">Aún no hay fechas calculables.</div>'}</div>${hidden?`<button class="btn full" onclick="calendarExpanded=true;renderDocs()">Mostrar ${hidden} eventos más</button>`:''}<div class="section-split"><div class="section-cap">Documentos</div><button class="text-link" onclick="openDocumentsModal()">Abrir</button></div><div class="doc-mini-grid">${docItems.slice(0,4).map(renderDocChip).join('')||'<div class="empty">Sin documentos configurados.</div>'}</div>`; }
function renderHistory(){ const totals={}; let totalCost=0; data.records.forEach(r=>{ const i=itemById(r.itemId)||{}; const g=categoryGroup(i.category||'Otros'); totals[g]=(totals[g]||0)+Number(r.cost)||0; totalCost+=Number(r.cost)||0; }); const ordered=Object.entries(totals).sort((a,b)=>b[1]-a[1]).slice(0,5); document.getElementById('history').innerHTML=`<div class="topbar-dual"><button class="back" onclick="go('home')">‹</button><h1 class="brand">ESTADÍSTICAS</h1><button class="ghost-btn"></button></div><div class="panel"><div class="stat-wrap"><div class="donut"><div class="donut-inner"><div><b>${money(totalCost)}</b><span>Total</span></div></div></div><div class="legend">${ordered.length?ordered.map(([name,val])=>`<div class="legend-row"><div class="legend-left"><i style="background:${accentForCategory(name)}"></i><span>${esc(name)}</span></div><div>${Math.round((val/Math.max(totalCost,1))*100)}% &nbsp; ${money(val)}</div></div>`).join(''):'<div class="tiny">Aún no hay gastos registrados.</div>'}</div></div></div><div class="section-cap">Historial reciente</div><div class="edit-hint">Toca cualquier registro para modificar fecha, km, costo, taller o notas.</div><div class="list-compact">${[...data.records].slice(0,8).map(r=>{const i=itemById(r.itemId)||{}; return `<div class="record-row editable" onclick="openRecordEditor('${r.id}')"><div class="left"><div class="icon-badge circle" style="color:${accentForCategory(i.category||'Otros')};width:40px;height:40px;font-size:18px">${iconForCategory(i.category||'Otros')}</div><div class="row-main"><b>${esc(i.name||'Registro')}</b><small>${fmtDate(r.date)} · ${r.quickCheck?'solo revisado':(r.km?Number(r.km).toLocaleString('es-CL')+' km':'sin km')}</small></div></div><div class="right">${money(r.cost)}<small>Editar</small></div></div>`}).join('')||'<div class="empty">Sin historial.</div>'}<button class="btn full" onclick="exportCsv()">Exportar CSV</button></div>`; }
function renderSettings(){ const reminders=['remKm1000','remOil3000','remAnnual','remDocs'].filter(k=>reminderSetting(k)).length; const motorPoints=data.items.filter(i=>!isDoc(i)&&categoryGroup(i.category)==='Motor').length; document.getElementById('settings').innerHTML=`<div class="topbar-dual"><button class="back" onclick="go('home')">‹</button><h1 class="brand">MÁS</h1><button class="icon-btn" onclick="toast('Opciones')">⋮</button></div><div class="settings-hub"><div class="settings-card" onclick="openVehicleSettings()"><div class="settings-ico">🚗</div><div><b>Vehículo</b><small>${esc(data.vehicle.name||'Vehículo')} · ${esc(data.vehicle.plate||'Sin patente')} · ${Number(data.vehicle.currentKm||0).toLocaleString('es-CL')} km</small></div><div class="chev">Editar</div></div><div class="settings-card" onclick="openReminderSettings()"><div class="settings-ico">🔔</div><div><b>Recordatorios</b><small>${reminders} activos · controles por km, aceite, anual y documentos</small></div><div class="chev">Abrir</div></div><div class="settings-card yellow" onclick="openMap('Motor')"><div class="settings-ico">🗺</div><div><b>Mapa del motor</b><small>${motorPoints} puntos de motor · vista editable por categoría</small></div><div class="chev">Abrir</div></div><div class="settings-card purple" onclick="go('history')"><div class="settings-ico">📊</div><div><b>Historial y estadísticas</b><small>Gastos, últimos registros y exportación CSV</small></div><div class="chev">Ver</div></div><div class="settings-card" onclick="openBackupSettings()"><div class="settings-ico">💾</div><div><b>Datos y respaldo</b><small>Guardar, compartir o importar JSON</small></div><div class="chev">Abrir</div></div><div class="settings-card" onclick="checkUpdates()"><div class="settings-ico">⬆</div><div><b>Actualización</b><small id="updateBox">Versión instalada: ${nativeVersion()}</small></div><div class="chev">Buscar</div></div></div><div class="footer-note">🛡 Todo bajo control</div>`; }
function openVehicleSettings(){ pendingVehicleImage=null; document.getElementById('modalRoot').innerHTML=`<div class="modal"><div class="modal-card compact-modal"><div class="modal-head"><h2>Vehículo</h2><button class="close" onclick="closeModal()">×</button></div><div class="form"><div class="vehicle-preview"><img id="vehPreview" src="${escAttr(vehicleSrc())}" alt="vehículo"></div><label class="file-mini">Cambiar foto real del auto<input type="file" accept="image/*" onchange="previewVehicleImage(this)"></label><div class="field"><label>Nombre</label><input class="input" id="vehName" value="${esc(data.vehicle.name||'')}"></div><div class="form2"><div class="field"><label>Año</label><input class="input" id="vehYear" value="${esc(data.vehicle.year||'')}"></div><div class="field"><label>Patente</label><input class="input" id="vehPlate" value="${esc(data.vehicle.plate||'')}"></div></div><div class="field"><label>Kilometraje</label><input class="input" type="number" id="vehKm" value="${Number(data.vehicle.currentKm)||''}"></div><div class="form-actions-2"><button class="btn danger-soft" onclick="resetVehicleImage()">Usar silueta</button><button class="btn primary" onclick="saveVehicleSettings()">Guardar</button></div></div></div></div>`; }
function previewVehicleImage(input){const f=input.files&&input.files[0]; if(!f)return; if(!String(f.type||'').startsWith('image/')){alert('Selecciona una imagen válida');return;} if(f.size>900000){alert('La imagen es muy pesada. Usa una foto recortada o comprimida.');return;} const r=new FileReader(); r.onload=()=>{pendingVehicleImage=String(r.result||''); const img=document.getElementById('vehPreview'); if(img)img.src=pendingVehicleImage;}; r.readAsDataURL(f);}
function resetVehicleImage(){pendingVehicleImage=DEFAULT_IMG; const img=document.getElementById('vehPreview'); if(img)img.src=DEFAULT_IMG;}
function saveVehicleSettings(){ data.vehicle.name=document.getElementById('vehName').value.trim()||'Vehículo'; data.vehicle.year=document.getElementById('vehYear').value.trim(); data.vehicle.plate=document.getElementById('vehPlate').value.trim(); data.vehicle.currentKm=Number(document.getElementById('vehKm').value)||0; if(pendingVehicleImage!==null)data.vehicle.image=pendingVehicleImage; pendingVehicleImage=null; save(); closeModal(); toast('Vehículo guardado'); render(); }
function openReminderSettings(){ const rows=[['remKm1000','Control cada 1.000 km','Fluidos, luces, neumáticos, etc.'],['remOil3000','Nivel de aceite cada 3.000 km','Chequeo preventivo.'],['remAnnual','Revisión anual','Aunque no alcances el kilometraje.'],['remDocs','Vencimiento documentos','Permiso, seguro y revisión técnica.']].map(([key,title,sub])=>`<div class="toggle-row" onclick="toggleReminderModal('${key}')"><div class="toggle-copy"><b>${title}</b><small>${sub}</small></div><div class="switch ${reminderSetting(key)?'on':''}"><span></span></div></div>`).join(''); document.getElementById('modalRoot').innerHTML=`<div class="modal"><div class="modal-card compact-modal"><div class="modal-head"><h2>Recordatorios</h2><button class="close" onclick="closeModal()">×</button></div><div class="compact-modal-list">${rows}</div></div></div>`; }
function toggleReminderModal(key){ data.settings[key]=!reminderSetting(key,true); save(); openReminderSettings(); renderSettings(); }
function openBackupSettings(){ document.getElementById('modalRoot').innerHTML=`<div class="modal"><div class="modal-card compact-modal"><div class="modal-head"><h2>Datos y respaldo</h2><button class="close" onclick="closeModal()">×</button></div><div class="backup-grid"><button class="btn" onclick="exportJson()">Guardar JSON</button><button class="btn" onclick="shareJson()">Compartir JSON</button></div><input type="file" id="importFile" accept="application/json,.json" style="display:none" onchange="importJsonFile(event)"><button class="btn full" onclick="document.getElementById('importFile').click()">Importar JSON</button><button class="btn full" onclick="checkUpdates()">Buscar actualizaciones</button><div class="version-line"><span id="updateBox">Versión instalada: ${nativeVersion()}</span></div></div></div>`; }
function openRegister(category, selectedId){const items=data.items.filter(i=>!isDoc(i) && (!category || categoryGroup(i.category)===category)); const pre=selectedId||items[0]?.id||''; modal=`register:${category||''}`; document.getElementById('modalRoot').innerHTML=`<div class="modal"><div class="modal-card"><div class="modal-head"><h2>Registrar mantención</h2><button class="close" onclick="closeModal()">×</button></div><div class="form"><div class="field"><label>Parte</label><select id="regItem">${items.map(i=>`<option value="${escAttr(i.id)}" ${i.id===pre?'selected':''}>${esc(i.name)} · ${esc(categoryGroup(i.category))}</option>`).join('')}</select></div><div class="form2"><div class="field"><label>Fecha</label><input class="input" type="date" id="regDate" value="${today()}"></div><div class="field"><label>Kilometraje</label><input class="input" type="number" id="regKm" value="${Number(data.vehicle.currentKm)||''}"></div></div><div class="form2"><div class="field"><label>Costo</label><input class="input" type="number" id="regCost" placeholder="0"></div><div class="field"><label>Taller / lugar</label><input class="input" id="regShop" placeholder="Opcional"></div></div><div class="field"><label>Notas</label><textarea id="regNotes" placeholder="Ej: 5W40 C3, marca, observaciones"></textarea></div><button class="btn primary" onclick="saveRecord()">Guardar mantención</button></div></div></div>`}
function saveRecord(){const itemId=document.getElementById('regItem').value; const kmRaw=document.getElementById('regKm').value.trim(); const rec={id:uid(),itemId,date:document.getElementById('regDate').value||today(),km:kmRaw===''?null:Number(kmRaw)||null,cost:Number(document.getElementById('regCost').value)||0,shop:document.getElementById('regShop').value.trim(),notes:document.getElementById('regNotes').value.trim(),quickCheck:false,createdAt:new Date().toISOString()}; data.records.unshift(rec); if(rec.km&&rec.km>data.vehicle.currentKm)data.vehicle.currentKm=rec.km; save(); closeModal(); toast('Mantención guardada'); render();}
function openRecordEditor(recordId){const r=recordById(recordId); if(!r){toast('Registro no encontrado');return;} const item=itemById(r.itemId)||{}; const isDocument=isDoc(item); const selectable=data.items.filter(i=>isDocument?isDoc(i):!isDoc(i)); const typeField=isDocument?'':`<div class="field"><label>Tipo de registro</label><select id="editQuick"><option value="service" ${!r.quickCheck?'selected':''}>Mantención real · reinicia vida útil</option><option value="check" ${r.quickCheck?'selected':''}>Solo revisado · no reinicia vida útil</option></select></div>`; const docFields=isDocument?`<div class="form2"><div class="field"><label>Fecha otorgada</label><input class="input" type="date" id="editIssue" value="${escAttr(r.issueDate||r.date||today())}"></div><div class="field"><label>Fecha vencimiento</label><input class="input" type="date" id="editExpiry" value="${escAttr(r.expiryDate||'')}"></div></div>`:''; document.getElementById('modalRoot').innerHTML=`<div class="modal"><div class="modal-card"><div class="topbar-dual" style="margin-bottom:10px"><button class="back" onclick="openItem('${r.itemId}','history')">‹</button><h1 class="brand" style="font-size:16px">EDITAR REGISTRO</h1><button class="icon-btn" onclick="deleteRecord('${recordId}')">🗑</button></div><div class="form"><div class="field"><label>${isDocument?'Documento':'Parte'}</label><select id="editItem">${selectable.map(i=>`<option value="${escAttr(i.id)}" ${i.id===r.itemId?'selected':''}>${esc(i.name)} · ${esc(categoryGroup(i.category))}</option>`).join('')}</select></div>${typeField}<div class="form2"><div class="field"><label>Fecha</label><input class="input" type="date" id="editDate" value="${escAttr(r.date||today())}"></div><div class="field"><label>Kilometraje</label><input class="input" type="number" id="editKm" value="${r.km!==null&&r.km!==undefined?Number(r.km):''}"></div></div><div class="form2"><div class="field"><label>Costo</label><input class="input" type="number" id="editCost" value="${Number(r.cost)||0}"></div><div class="field"><label>Taller / lugar</label><input class="input" id="editShop" value="${escAttr(r.shop||'')}" placeholder="Opcional"></div></div>${docFields}<div class="field"><label>Notas</label><textarea id="editNotes" placeholder="Observaciones">${esc(r.notes||'')}</textarea></div><div class="action-grid"><button class="btn danger" onclick="deleteRecord('${recordId}')">Borrar</button><button class="btn primary" onclick="saveEditedRecord('${recordId}')">Guardar cambios</button></div></div></div></div>`;}
function saveEditedRecord(recordId){const idx=data.records.findIndex(r=>r.id===recordId); if(idx<0){toast('Registro no encontrado');return;} const old=data.records[idx]; const itemId=document.getElementById('editItem').value; const item=itemById(itemId)||{}; const kmRaw=document.getElementById('editKm').value.trim(); const rec={...old,itemId,date:document.getElementById('editDate').value||today(),km:kmRaw===''?null:Number(kmRaw)||null,cost:Number(document.getElementById('editCost').value)||0,shop:document.getElementById('editShop').value.trim(),notes:document.getElementById('editNotes').value.trim(),updatedAt:new Date().toISOString()}; if(isDoc(item)){rec.issueDate=document.getElementById('editIssue')?.value||rec.date; rec.expiryDate=document.getElementById('editExpiry')?.value||''; rec.date=rec.issueDate; rec.quickCheck=false;}else{rec.quickCheck=document.getElementById('editQuick')?.value==='check'; delete rec.issueDate; delete rec.expiryDate;} data.records[idx]=rec; if(rec.km&&rec.km>data.vehicle.currentKm)data.vehicle.currentKm=rec.km; save(); toast('Registro actualizado'); render(); openItem(itemId,'history');}
function deleteRecord(recordId){const r=recordById(recordId); if(!r){toast('Registro no encontrado');return;} const itemId=r.itemId; if(!confirm('¿Borrar este registro? Esta acción no se puede deshacer.'))return; data.records=data.records.filter(x=>x.id!==recordId); save(); toast('Registro borrado'); render(); openItem(itemId,'history');}
function openDoc(id){const item=itemById(id); const rec=lastRecord(id)||{}; document.getElementById('modalRoot').innerHTML=`<div class="modal"><div class="modal-card"><div class="modal-head"><h2>${esc(item.name)}</h2><button class="close" onclick="closeModal()">×</button></div><div class="form"><div class="form2"><div class="field"><label>Fecha otorgada</label><input class="input" type="date" id="docIssue" value="${esc(rec.issueDate||rec.date||today())}"></div><div class="field"><label>Fecha vencimiento</label><input class="input" type="date" id="docExpiry" value="${esc(rec.expiryDate||'')}"></div></div><div class="field"><label>Lugar / nota corta</label><input class="input" id="docShop" value="${esc(rec.shop||'')}" placeholder="Opcional"></div><button class="btn primary" onclick="saveDoc('${id}')">Guardar documento</button></div></div></div>`}
function saveDoc(id){const issue=document.getElementById('docIssue').value||today(); const expiry=document.getElementById('docExpiry').value; data.records.unshift({id:uid(),itemId:id,date:issue,km:0,cost:0,shop:document.getElementById('docShop').value.trim(),notes:'',issueDate:issue,expiryDate:expiry,createdAt:new Date().toISOString()}); save(); closeModal(); toast('Documento guardado'); render();}
function openItem(id,section='summary'){const item=itemById(id); const st=statusOf(item); const rec=isDoc(item)?lastRecord(id):lastServiceRecord(id); const p=progressData(item); const due=serviceRight(item,st); const history=recordsOf(id); const summary=`<div class="detail-section"><div class="panel slim"><div class="split-two"><div><div class="tiny">ESTADO</div><div class="big-number">${st.state==='critical'?'Pendiente':st.state==='warning'?'Próxima':'OK'}</div></div><div><div class="tiny">ÚLTIMA REVISIÓN</div><div class="big-number" style="font-size:26px">${rec?fmtDate(rec.date):'Sin dato'}</div></div></div><div class="progress-wrap"><div class="progressbar" style="--pct:${p.pct}%"><span></span></div><div class="metric-labels"><span>${item.intervalKm?`cada ${Number(item.intervalKm).toLocaleString('es-CL')} km`:'control por fecha'}</span><span>${item.intervalMonths?(item.intervalMonths===12?'1 año':item.intervalMonths+' meses'):'sin vencimiento fijo'}</span></div></div></div><div class="detail-grid"><div class="detail-stat"><label>Próximo control</label><b>${esc(due.top)}</b><small>${esc(due.bottom)}</small></div><div class="detail-stat"><label>Intervalo</label><b>${esc(intervalText(item))}</b><small>${esc(categoryGroup(item.category))}</small></div><div class="detail-stat"><label>Kilometraje actual</label><b>${Number(data.vehicle.currentKm||0).toLocaleString('es-CL')} km</b><small>${rec&&rec.km!==null&&rec.km!==undefined?`Último registro en ${Number(rec.km||0).toLocaleString('es-CL')} km`:'Sin km registrado'}</small></div>${supportsQuickCheck(item)?'<div class="detail-stat"><label>Chequeo rápido</label><b>✅ Solo revisado</b><small>No reinicia kilometraje ni fecha de cambio.</small></div>':'<div class="detail-stat"><label>Registro</label><b>Mantención real</b><small>Usa Registrar mantención para reiniciar vida útil.</small></div>'}</div></div>`; const details=`<div class="detail-section"><div class="detail-grid"><div class="detail-stat"><label>Categoría</label><b>${esc(categoryGroup(item.category))}</b><small>${esc(item.category||'')}</small></div><div class="detail-stat"><label>Tipo</label><b>${item.intervalKm||item.intervalMonths?'Periódico':'Manual'}</b><small>${supportsQuickCheck(item)?'Chequeo rápido disponible; no reinicia vencimiento.':'Requiere registro manual.'}</small></div></div>${item.note?`<div class="detail-note"><div class="tiny" style="margin-bottom:6px">NOTA / MANUAL</div>${esc(item.note)}</div>`:''}<div class="detail-note"><div class="tiny" style="margin-bottom:6px">FUENTE</div>${esc(item.source||'Sin fuente')}</div></div>`; const historyHtml=history.length?`<div class="edit-hint">Toca un registro para modificarlo o borrarlo.</div><div class="history-stack">${history.map(r=>`<div class="record-row editable" onclick="openRecordEditor('${r.id}')"><div class="left"><div class="icon-badge circle" style="color:${accentForCategory(item.category)};width:38px;height:38px;font-size:16px">${iconForCategory(item.category)}</div><div class="row-main"><b>${fmtDate(r.date)}</b><small>${r.quickCheck?'Solo revisado ✅':`${r.km?Number(r.km).toLocaleString('es-CL')+' km':'sin km'} · ${esc(r.shop||'sin taller')}`}${r.notes?` · ${esc(r.notes)}`:''}</small></div></div><div class="right">${money(r.cost)}<small>Editar</small></div></div>`).join('')}</div>`:'<div class="history-empty">Aún no hay historial para este ítem.</div>'; const body=section==='details'?details:section==='history'?historyHtml:summary; modal=`item:${id}:${section}`; document.getElementById('modalRoot').innerHTML=`<div class="modal"><div class="modal-card"><div class="topbar-dual" style="margin-bottom:10px"><button class="back" onclick="closeModal()">‹</button><h1 class="brand" style="font-size:16px">DETALLE</h1><button class="icon-btn" onclick="editItem('${id}')">✎</button></div><div class="detail-hero"><div class="icon-badge circle" style="color:${accentForCategory(item.category)}">${iconForCategory(item.category)}</div><div><div class="detail-title">${esc(item.name)}</div><div class="mini-note" style="margin-top:5px">${esc(categoryGroup(item.category))}</div><div class="status ${st.state}" style="margin-top:9px">${st.state==='critical'?'Pendiente':stateLabel(st.state)}</div></div></div><div class="maintenance-tabs" style="margin-bottom:12px"><button class="seg ${section==='summary'?'active':''}" onclick="openItem('${id}','summary')">RESUMEN</button><button class="seg ${section==='details'?'active':''}" onclick="openItem('${id}','details')">DETALLES</button><button class="seg ${section==='history'?'active':''}" onclick="openItem('${id}','history')">HISTORIAL</button></div><div class="detail-body">${body}</div><div class="detail-actions">${supportsQuickCheck(item)?`<button class="btn soft smallish" onclick="quickCheck('${id}')">✅ Solo revisado</button>`:'<button class="btn soft smallish" onclick="closeModal()">Cerrar</button>'}<button class="btn primary smallish" onclick="closeModal();openRegister('${categoryGroup(item.category)}','${id}')">Registrar mantención</button></div></div></div>`}
function editItem(id){const item=itemById(id); const name=prompt('Nombre',item.name); if(name===null)return; item.name=name.trim()||item.name; const category=prompt('Categoría',item.category||'Motor'); if(category===null)return; item.category=category.trim()||item.category; const km=prompt('Intervalo km vacío = sin control por km',item.intervalKm??''); if(km!==null)item.intervalKm=String(km).trim()===''?null:Number(km)||null; const months=prompt('Intervalo meses vacío = sin control por fecha',item.intervalMonths??''); if(months!==null)item.intervalMonths=String(months).trim()===''?null:Number(months)||null; save(); closeModal(); render();}
function openMap(category){if(category)cat=category; const visible=data.items.filter(i=>!isDoc(i)&&categoryGroup(i.category)===cat); document.getElementById('modalRoot').innerHTML=`<div class="modal"><div class="modal-card"><div class="modal-head"><h2>Mapa del ${cat.toLowerCase()}</h2><button class="close" onclick="closeModal()">×</button></div><div class="pills">${MAP_CATEGORIES.map(c=>`<button class="pill ${cat===c?'active':''}" onclick="cat='${c}';openMap(c)">${c}</button>`).join('')}</div><p class="tiny">Toca un punto para revisar. Mantén y arrastra para moverlo si quieres reorganizar el plano.</p><div class="map-scroll"><div id="bigMap" class="maparea map-large"><img src="${escAttr(usesEngineMap()?ENGINE_IMG:vehicleSrc())}">${visible.map(renderDot).join('')}</div></div><button class="btn full" onclick="addPointPrompt()">Agregar punto en esta categoría</button></div></div>`; setTimeout(bindBigMap,0)}
function pointFor(i){const key=usesEngineMap()?'motor':'vehicle'; const p=i.points&&i.points[key]; if(p&&typeof p.x==='number')return p; return {x:Number(i.x||50),y:Number(i.y||50)}}
function setPoint(i,x,y){const key=usesEngineMap()?'motor':'vehicle'; i.points=i.points||{}; i.points[key]={x,y}; if(key==='vehicle'){i.x=x;i.y=y}}
function renderDot(i){const st=statusOf(i).state; const p=pointFor(i); return `<div class="dot ${dotClass(st)}" data-id="${i.id}" style="left:${p.x}%;top:${p.y}%"><span class="label">${esc(i.name)}</span></div>`}
function bindBigMap(){const map=document.getElementById('bigMap'); if(!map)return; const pos=(e)=>{const r=map.getBoundingClientRect(); return {x:Math.max(2,Math.min(98,(e.clientX-r.left)/r.width*100)),y:Math.max(2,Math.min(98,(e.clientY-r.top)/r.height*100))}}; map.querySelectorAll('.dot').forEach(dot=>{dot.addEventListener('click',e=>{e.stopPropagation();openItem(dot.dataset.id)}); dot.addEventListener('pointerdown',e=>{e.stopPropagation(); dragId=dot.dataset.id; dragMoved=false; try{dot.setPointerCapture(e.pointerId)}catch(_){} }); dot.addEventListener('pointermove',e=>{if(dragId!==dot.dataset.id)return; const item=itemById(dragId); const p=pos(e); setPoint(item,p.x,p.y); dot.style.left=p.x+'%'; dot.style.top=p.y+'%'; dragMoved=true;}); dot.addEventListener('pointerup',e=>{if(dragId){save(); if(dragMoved)toast('Punto movido'); dragId=null; dragMoved=false;}});});}
function addPointPrompt(){const name=prompt('Nombre de la parte'); if(!name)return; const item={id:uid(),name:name.trim(),category:cat,x:50,y:50,intervalKm:null,intervalMonths:null,points:{},document:false}; data.items.push(item); save(); openMap(cat); toast('Punto creado al centro. Arrástralo.');}

function closeModal(){document.getElementById('modalRoot').innerHTML=''; modal=null;}
function updateKm(){const km=prompt('Kilometraje actual',data.vehicle.currentKm||''); if(km===null)return; data.vehicle.currentKm=Number(km)||0; save(); toast('Km actualizado'); render();}
function saveVehicle(){data.vehicle.name=document.getElementById('vehName').value.trim()||'Vehículo'; data.vehicle.year=document.getElementById('vehYear').value.trim(); data.vehicle.plate=document.getElementById('vehPlate').value.trim(); data.vehicle.currentKm=Number(document.getElementById('vehKm').value)||0; save(); toast('Vehículo guardado'); renderSettings();}
function exportDataObj(){return {...data,exportedAt:new Date().toISOString()}}
function exportJson(){const json=JSON.stringify(exportDataObj(),null,2); const name='mi-auto-respaldo-'+today()+'.json'; if(window.AndroidBridge?.saveJson)AndroidBridge.saveJson(name,json); else download(name,json,'application/json')}
function shareJson(){const json=JSON.stringify(exportDataObj(),null,2); const name='mi-auto-respaldo-'+today()+'.json'; if(window.AndroidBridge?.shareJson)AndroidBridge.shareJson(name,json); else download(name,json,'application/json')}
function importJsonFile(e){const f=e.target.files&&e.target.files[0]; if(!f)return; const r=new FileReader(); r.onload=()=>{try{const obj=JSON.parse(r.result); if(!obj.vehicle||!Array.isArray(obj.items))throw new Error('JSON inválido'); data=migrate(obj); save(); toast('JSON importado'); go('home');}catch(err){alert('No se pudo importar: '+err.message)}}; r.readAsText(f)}
function csvCell(v){return '"'+String(v??'').replace(/"/g,'""')+'"'}
function exportCsv(){const header=['fecha','elemento','categoria','km','costo','taller','notas','vence']; const rows=data.records.map(r=>{const i=itemById(r.itemId)||{}; return [r.date,i.name||'',i.category||'',r.km||'',r.cost||'',r.shop||'',r.notes||'',r.expiryDate||''].map(csvCell).join(',')}); const csv=header.join(',')+'\n'+rows.join('\n'); if(window.AndroidBridge?.saveCsv)AndroidBridge.saveCsv('mi-auto-historial-'+today()+'.csv',csv); else download('mi-auto-historial.csv',csv,'text/csv')}
function download(name,content,type){const a=document.createElement('a'); a.href=URL.createObjectURL(new Blob([content],{type})); a.download=name; a.click(); setTimeout(()=>URL.revokeObjectURL(a.href),1000)}
function checkUpdates(){const box=document.getElementById('updateBox'); if(box)box.textContent='Buscando...'; if(window.AndroidBridge?.checkGithubUpdates)AndroidBridge.checkGithubUpdates(); else if(box)box.textContent='Disponible solo en APK'}
window.onNativeUpdateResult=(res)=>{const box=document.getElementById('updateBox'); if(!box)return; if(!res||!res.ok){box.textContent='Error: '+(res?.error||'sin respuesta');return;} box.innerHTML=`Última: <b>${esc(res.tagName)}</b>. <button class="btn small" onclick="AndroidBridge.openUpdateUrl('${esc(res.apkUrl||res.htmlUrl)}')">Abrir</button>`}
function nativeVersion(){try{return window.AndroidBridge?.getVersionName?.()||APP_VERSION}catch(e){return APP_VERSION}}
function toast(msg){const t=document.getElementById('toast'); t.textContent=msg; t.style.display='block'; clearTimeout(window.__toast); window.__toast=setTimeout(()=>t.style.display='none',1800)}
function appBack(){if(document.getElementById('modalRoot').innerHTML){closeModal();return 'handled'} if(view!=='home'){go('home');return 'handled'} return 'exit'}
window.appBack=appBack;
render();
